sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	var gaValidateValue, intervalValidatingMsg;
	var valueFieldName = 'value';
	var isAdvanced = g_form.getValue('advanced') === 'true';

	if (newValue === '') {
		return;
	}
	//Unable to validate scripted values client-side.
	if (isAdvanced) {
		return;
	}

	gaValidateValue = new GlideAjax('x_taniu_tan_core.ConfiguredSensorAJAX');
	gaValidateValue.addParam('sysparm_name', 'getPromptAndHelpText');
	gaValidateValue.addParam('sensor_param_sys_id', g_form.getValue('sensor_parameter'));
	gaValidateValue.getXMLAnswer(function (answer) {
		var placeholderText, helpText;

		answer = JSON.parse(answer);
		placeholderText = answer.prompt_text;
		helpText = answer.help_text;

		try {
			g_form.getControl('value').placeholder = placeholderText;
		} catch(ex) {
			console.debug(
				'Unable to set placeholder text on value field. Error: \n' + ex.message
			);
		}

		//g_form.showFieldMsg('value', helpText, 'info');
		if (helpText) {
			g_form.showFieldMsg(
				'value_script',
				('Parameter help text: ' + helpText),
				'info'
			);
		}

	});
	//Show prompt message on both value and value script field
	// on load only (???)

}
